#!/bin/bash# ============================================================#  deploy.sh â€“ Deploy AutoCategory##  DÃ¹ng:#    ./deploy.sh          â†’ full deploy (prod, cÃ³ CF tunnel)#    ./deploy.sh --dev    â†’ full deploy (dev, khÃ´ng CF)#    ./deploy.sh --api    â†’ chá»‰ rebuild & restart service api#    ./deploy.sh --help# ============================================================set -euo pipefailCOMPOSE_DEV="docker-compose -f docker-compose.yml"COMPOSE_PROD="docker-compose -f docker-compose.yml -f docker-compose.prod.yml"usage() {  cat <<EOFCÃ¡ch dÃ¹ng:  ./deploy.sh           Full deploy prod  (cÃ³ Cloudflare tunnel)  ./deploy.sh --dev     Full deploy dev   (khÃ´ng Cloudflare, expose port 80)  ./deploy.sh --api     Chá»‰ rebuild + restart service api (khÃ´ng Ä‘á»¥ng Ollama/Qdrant)  ./deploy.sh --help    Hiá»ƒn thá»‹ trá»£ giÃºp nÃ yEOF}log()  { echo "[$(date '+%H:%M:%S')] $*"; }ok()   { echo "[$(date '+%H:%M:%S')] âœ…  $*"; }err()  { echo "[$(date '+%H:%M:%S')] âŒ  $*" >&2; }# â”€â”€ Kiá»ƒm tra .env â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€check_env() {  if [ ! -f .env ]; then    err ".env khÃ´ng tá»“n táº¡i. Cháº¡y: cp .env.example .env rá»“i Ä‘iá»n thÃ´ng tin."    exit 1  fi}# â”€â”€ Build image api â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€build_api() {  local compose_cmd=$1  log "Build image api ..."  $compose_cmd build --no-cache api}# â”€â”€ Full deploy â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€deploy_full() {  local compose_cmd=$1  local mode=$2  log "=== Full deploy ($mode) ==="  check_env  # Pull images má»›i nháº¥t (trá»« service build)  log "Pull images ..."  $compose_cmd pull --ignore-buildable  # Build image cá»§a api  log "Build api image ..."  $compose_cmd build api  # Khá»Ÿi Ä‘á»™ng toÃ n bá»™ stack (detach)  log "Khá»Ÿi Ä‘á»™ng stack ..."  $compose_cmd up -d --remove-orphans  # Chá» api healthy  log "Chá» api sáºµn sÃ ng ..."  wait_healthy "autocategory_api" 120  ok "Stack Ä‘ang cháº¡y."  echo ""  if [ "$mode" = "prod" ]; then    echo "  ðŸŒ  Truy cáº­p: https://$(grep CF_SUBDOMAIN .env | cut -d= -f2).$(grep CF_DOMAIN .env | cut -d= -f2)"    echo "       (Cloudflare tunnel cÃ³ thá»ƒ máº¥t 10â€“30s Ä‘á»ƒ kÃ­ch hoáº¡t)"  else    echo "  ðŸŒ  Truy cáº­p: http://localhost"  fi  echo ""  build_index_hint}# â”€â”€ Chá»‰ deploy api â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€deploy_api_only() {  log "=== Cáº­p nháº­t api (khÃ´ng rebuild Ollama/Qdrant) ==="  check_env  # XÃ¡c Ä‘á»‹nh compose command (prod hay dev dá»±a vÃ o container Ä‘ang cháº¡y)  local compose_cmd  if docker ps --format '{{.Names}}' | grep -q "autocategory_cloudflared"; then    compose_cmd=$COMPOSE_PROD    log "PhÃ¡t hiá»‡n stack prod (cloudflared Ä‘ang cháº¡y)"  else    compose_cmd=$COMPOSE_DEV    log "PhÃ¡t hiá»‡n stack dev"  fi  log "Build api image ..."  $compose_cmd build --no-cache api  log "Restart api (zero-downtime: stop â†’ start) ..."  $compose_cmd stop api  $compose_cmd rm -f api  $compose_cmd up -d api  log "Chá» api sáºµn sÃ ng ..."  wait_healthy "autocategory_api" 90  ok "api Ä‘Ã£ cáº­p nháº­t."  echo ""  build_index_hint}# â”€â”€ Chá» container healthy â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€wait_healthy() {  local name=$1  local max=$2  local i=0  while [ $i -lt $max ]; do    status=$(docker inspect --format='{{.State.Health.Status}}' "$name" 2>/dev/null || echo "missing")    case "$status" in      healthy) return 0 ;;      unhealthy)        err "Container $name bÃ¡o unhealthy. Xem log: docker logs $name"        exit 1        ;;    esac    printf "."    sleep 2    i=$((i + 2))  done  echo ""  err "Timeout chá» $name healthy. Xem log: docker logs $name"  exit 1}# â”€â”€ Gá»£i Ã½ build index â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€build_index_hint() {  # Kiá»ƒm tra index Ä‘Ã£ cÃ³ chÆ°a  local count  count=$(curl -sf http://localhost/api/admin/index-info 2>/dev/null \    | grep -o '"vectors_count":[0-9]*' | grep -o '[0-9]*' || echo "0")  if [ "$count" = "0" ] || [ -z "$count" ]; then    echo "  â„¹ï¸   Index chÆ°a cÃ³ dá»¯ liá»‡u. Cháº¡y lá»‡nh sau Ä‘á»ƒ build:"    echo "       curl -X POST http://localhost/api/admin/build-index"    echo "       (hoáº·c POST https://DOMAIN/api/admin/build-index khi dÃ¹ng prod)"  else    echo "  â„¹ï¸   Index hiá»‡n cÃ³ $count vectors."  fi}# â”€â”€ Main â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€MODE=${1:-""}case "$MODE" in  "")        deploy_full "$COMPOSE_PROD" "prod" ;;  --dev)     deploy_full "$COMPOSE_DEV"  "dev"  ;;  --api)     deploy_api_only ;;  --help|-h) usage ;;  *)    err "Tham sá»‘ khÃ´ng há»£p lá»‡: $MODE"    usage    exit 1    ;;esac